mapper.insert:
INSERT INTO monitor_alert_rule (
  project_id, name, event_type, threshold_count, window_minutes, enabled
) VALUES (
  #{projectId}, #{name}, #{eventType}, #{thresholdCount}, #{windowMinutes}, #{enabled}
)

mapper.update:
UPDATE monitor_alert_rule
SET enabled = #{enabled}
WHERE id = #{id}

mapper.select:
SELECT id, project_id, name, event_type, threshold_count, window_minutes,
       enabled, create_time, update_time
FROM monitor_alert_rule


    AND project_id = #{projectId}


    AND enabled = #{enabled}


ORDER BY id DESC

mapper.insert:
INSERT INTO monitor_alert_record (
  rule_id, project_id, event_type, window_start, window_end,
  actual_count, threshold_count, message, triggered_at
) VALUES (
  #{ruleId}, #{projectId}, #{eventType}, #{windowStart}, #{windowEnd},
  #{actualCount}, #{thresholdCount}, #{message}, #{triggeredAt}
)

mapper.select:
SELECT id, rule_id, project_id, event_type, window_start, window_end,
       actual_count, threshold_count, message, triggered_at, create_time
FROM monitor_alert_record


    AND project_id = #{projectId}


    AND rule_id = #{ruleId}


    AND triggered_at  >=  #{startTime}


    AND triggered_at  <=  #{endTime}


ORDER BY triggered_at DESC, id DESC
